import React, { useState, useEffect } from 'react';

const Skills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);

  const frontendSkills = [
    { name: 'React', icon: '⚛️', desc: 'UI Library' },
    { name: 'Next.js', icon: '▲', desc: 'React Framework' },
    { name: 'TypeScript', icon: '📘', desc: 'Typed JS' },
    { name: 'JavaScript', icon: '⚡', desc: 'Programming' },
    { name: 'HTML5', icon: '🌐', desc: 'Markup' },
    { name: 'CSS3', icon: '🎨', desc: 'Styling' },
    { name: 'Tailwind CSS', icon: '💨', desc: 'Utility CSS' },
    { name: 'Redux', icon: '🔄', desc: 'State Mgmt' },
    { name: 'Framer Motion', icon: '🎬', desc: 'Animations' }
  ];

  const backendSkills = [
    { name: 'Node.js', icon: '🟢', desc: 'Runtime' },
    { name: 'Express.js', icon: '🚀', desc: 'Framework' },
    { name: 'MongoDB', icon: '🍃', desc: 'NoSQL DB' },
    { name: 'JWT', icon: '🔐', desc: 'Auth' },
    { name: 'REST API', icon: '🔗', desc: 'APIs' },
    { name: 'Socket.io', icon: '📡', desc: 'Real-time' },
    { name: 'Mongoose', icon: '📦', desc: 'ODM' },
    { name: 'Cloudinary', icon: '☁️', desc: 'Cloud Storage' }
  ];

  const allSkills = [...frontendSkills, ...backendSkills];

  return (
    <section id="skills" className="relative z-10 py-16 px-6 overflow-hidden">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">My Skills</h2>

        <div className="relative min-h-[600px] w-full flex items-center justify-center">
          {/* Background Glow */}
          <div className="absolute w-[500px] h-[500px] rounded-full bg-purple-500/5 blur-3xl"></div>

          {/* Outer Ring */}
          <div className="absolute w-[450px] h-[450px] rounded-full border border-purple-500/10 animate-spin-slow"></div>

          {/* Middle Ring */}
          <div className="absolute w-[350px] h-[350px] rounded-full border border-purple-400/15 animate-spin-slow-reverse"></div>

          {/* Inner Ring */}
          <div className="absolute w-[250px] h-[250px] rounded-full border border-purple-300/20 animate-spin-slow"></div>

          {/* Center Dot */}
          <div className="absolute w-4 h-4 rounded-full bg-purple-500/50 animate-pulse"></div>

          {/* Skills on Rings */}
          {allSkills.map((skill, index) => {
            const total = allSkills.length;
            const angle = (index / total) * 2 * Math.PI;

            // Distribute skills on different rings
            let radius = 0;
            const ringIndex = index % 3;
            if (ringIndex === 0) radius = 210; // Outer ring
            else if (ringIndex === 1) radius = 160; // Middle ring
            else radius = 110; // Inner ring

            const x = Math.cos(angle) * radius;
            const y = Math.sin(angle) * radius;

            // Different speeds for each ring
            const speed = ringIndex === 0 ? 'spin-slow' : ringIndex === 1 ? 'spin-slow-reverse' : 'spin-slow';
            const duration = ringIndex === 0 ? 20 : ringIndex === 1 ? 25 : 30;

            return (
              <div
                key={index}
                onMouseEnter={() => setHoveredSkill(skill.name)}
                onMouseLeave={() => setHoveredSkill(null)}
                className="absolute cursor-pointer transition-all duration-300"
                style={{
                  transform: `translate(${x}px, ${y}px)`,
                  animation: `${speed} ${duration}s linear infinite`,
                  transformOrigin: 'center',
                  zIndex: hoveredSkill === skill.name ? 50 : 10
                }}
              >
                <div 
                  className="flex flex-col items-center justify-center rounded-full backdrop-blur-sm transition-all duration-500"
                  style={{
                    width: hoveredSkill === skill.name ? '80px' : '60px',
                    height: hoveredSkill === skill.name ? '80px' : '60px',
                    boxShadow: hoveredSkill === skill.name ? '0 0 40px rgba(139,92,246,0.3)' : 'none',
                    transform: hoveredSkill === skill.name ? 'scale(1.2)' : 'scale(1)',
                    background: hoveredSkill === skill.name 
                      ? 'rgba(26,31,46,0.9)' 
                      : 'rgba(26,31,46,0.4)',
                    border: hoveredSkill === skill.name 
                      ? '1px solid rgba(139,92,246,0.5)' 
                      : '1px solid rgba(255,255,255,0.05)'
                  }}
                >
                  <span 
                    className="transition-all duration-500"
                    style={{ 
                      fontSize: hoveredSkill === skill.name ? '24px' : '18px',
                      filter: hoveredSkill === skill.name ? 'brightness(1.3)' : 'brightness(0.7)'
                    }}
                  >
                    {skill.icon}
                  </span>

                  {hoveredSkill === skill.name && (
                    <>
                      <span className="text-[9px] font-semibold text-white mt-0.5 animate-fadeIn">
                        {skill.name}
                      </span>
                      <span className="text-[7px] text-purple-300 animate-fadeIn">
                        {skill.desc}
                      </span>
                    </>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mt-8 glass-card rounded-2xl p-6">
          <div className="text-center">
            <div className="text-2xl font-bold text-white">20+</div>
            <div className="text-[10px] text-gray-500">Projects Completed</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">15+</div>
            <div className="text-[10px] text-gray-500">Happy Clients</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">2+</div>
            <div className="text-[10px] text-gray-500">Years Experience</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">2000+</div>
            <div className="text-[10px] text-gray-500">Cups of Coffee</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">5</div>
            <div className="text-[10px] text-gray-500">Technologies Mastered</div>
          </div>
        </div>

        {/* Hint text */}
        <div className="text-center text-gray-500 text-xs mt-4 opacity-60">
          Hover on any skill to see more ✨
        </div>
      </div>

      <style>{`
        @keyframes spin-slow {
          0% { transform: translate(0px, 0px) rotate(0deg); }
          100% { transform: translate(0px, 0px) rotate(360deg); }
        }
        @keyframes spin-slow-reverse {
          0% { transform: translate(0px, 0px) rotate(360deg); }
          100% { transform: translate(0px, 0px) rotate(0deg); }
        }
        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: scale(0.8);
          }
          to {
            opacity: 1;
            transform: scale(1);
          }
        }
        .animate-fadeIn {
          animation: fadeIn 0.25s ease-out forwards;
        }
        .animate-pulse {
          animation: pulse 2s ease-in-out infinite;
        }
        .animate-spin-slow {
          animation: spin-slow 20s linear infinite;
        }
        .animate-spin-slow-reverse {
          animation: spin-slow-reverse 25s linear infinite;
        }
        @keyframes pulse {
          0%, 100% { transform: scale(1); opacity: 0.5; }
          50% { transform: scale(1.5); opacity: 1; }
        }
      `}</style>
    </section>
  );
};

export default Skills;
